             </td>
             <td align="left" class="content" style="text-align: center;" width="266">
              <a class="image-link" href="https://email.mg2.substack.com/c/eJxVUsmOpDAM_ZriBsq-HDi0RprfQFkMFRUkTBK6p_rrO8BhNFJiO3myn-VnZyosKb_HPZXanWaq7x3GCF9lhVohd0eBPAU_YkEU5Ux3fmQeK666UKY5A2wmrGPNB3T7YdfgTA0pXhkIEd49R6YdzEIqSYwjAhCmkgmJHdOCi3meb15z-ADRwQifkN8pQreOz1r38qAfD_K7HefjUA5bqnGvwaWtfYXNLND8DNU9T9_K1PQgv_7cAf1YUvLtPa_TntOSoZTwCe2_VIC9ZdwUhJ8k_KRpxh7uBQ3PPSBurVOst8bQnlEJveZY9cZbSixIqRUbCh3MZr5TNF_l7qvVuGdxhVeT5QopmZ3CGvXeW94zhnRvvRC9JBhhZZCw0kxSib_tDntcujAS1DCFNCYcMzHgYeaaYQBHZu2wM0SdjQivMFeKgeMPhraF_DepLo8xVZtyiEuDX0-zwXoBrc2p-e2Iob4niMau4G81670Ul77TAhFyWxY_mXqtAse0DaJpeavX5KZaKkyo6hqzTy0r_iP9AXuwxx4" style="border: none; display: block; height: auto; margin: 0; padding: 0; text-decoration: none; width: auto;" target="_blank">
               <img alt="" class="" data-attrs='{"src":"https://bucketeer-e05bbc84-baa3-437e-9518-adb32be77984.s3.amazonaws.com/public/images/32fc8190-ddb5-4409-bd66-721018a06b7a_786x786.png","height":786,"width":786,"resizeWidth":266,"bytes":null,"alt":null,"title":null,"type":null,"href":null}' src="https://cdn.substack.com/image/fetch/w_266,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fbucketeer-e05bbc84-baa3-437e-9518-adb32be77984.s3.amazonaws.com%2Fpublic%2Fimages%2F32fc8190-ddb5-4409-bd66-721018a06b7a_786x786.png" style="-ms-interpolation-mode: bicubic; border: none !important; display: block; height: auto; margin: 0 auto; margin-bottom: 0; max-width: 100%; vertical-align: middle; width: auto;" width="266"/>
