         <a href="https://email.mg2.substack.com/c/eJxFkMGOhSAMRb_msTQUQWHBYjbzGwShKhkFAzgv_v3wdDFJ06Zp2tt7nK24pHzpI5VKPsnU60Ad8V02rBUzOQtmE7yGgclecEW85h6kkCQUM2fE3YZN13wiOc5pC87WkOK9QSkTZNUwCuXmcQQxKRx64CN4CoLPagJvFX107ekDRocafzFfKSLZ9FrrUV7914t9t6jv8Pmoc2lvnbExlNUuMayp5kCCZpQBlVQBE8CHDrpZKA6Ijs3KgbNMsgnHwUsQUnJ04sXpvrCunFOp1v18DpOsY6pTyiEubfyz2h23e9DMmVb3M4Z6GYx22tA_vuuD7yZhFoyYG1ZvbL2hCegFSAr947OB6dUogfWSNGWf2lb8F_0DKhyGtA" style="color: #1a1a1a; text-decoration: underline;">
          Anish Agnihotri
